def install_sdk():
    PKG.mkdir(parents=True, exist_ok=True)
    for rel, content in SDK_FILES.items():
        p = PKG / rel
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(content, encoding="utf-8")
        if p.suffix == ".py":
            py_compile.compile(str(p), doraise=True)
    bridge = PY / "208_Automation_SDK.py"
    bridge.write_text(BRIDGE_SDK, encoding="utf-8")
    py_compile.compile(str(bridge), doraise=True)

def install_generator():
    gen_dir = PKG / "generators"
    gen_dir.mkdir(parents=True, exist_ok=True)
    (gen_dir / "__init__.py").write_text("", encoding="utf-8")
    (gen_dir / "module_generator.py").write_text(GENERATOR_CODE, encoding="utf-8")
    (PY / "208_Module_Generator.py").write_text(RUNNER_GENERATOR, encoding="utf-8")
    py_compile.compile(str(gen_dir / "module_generator.py"), doraise=True)
    py_compile.compile(str(PY / "208_Module_Generator.py"), doraise=True)

def build_modules():
    sys.path.insert(0, str(PKG))
    from generators.module_generator import create_module
    results = []
    for module_id, name, bridge in MODULES:
        res = create_module(module_id, name, bridge_name=bridge, overwrite=True)
        results.append(res["payload"])
    return results

def main():
    PY.mkdir(parents=True, exist_ok=True)
    install_sdk()
    install_generator()
    results = build_modules()
    run_all_path = PY / "208_Run_All.py"
    run_all_path.write_text(RUN_ALL, encoding="utf-8")
    py_compile.compile(str(run_all_path), doraise=True)
    errors = []
    for r in results:
        errors.extend(r.get("errors", []))
    print("="*80)
    print("208 ALL-IN-ONE AUTOMATION LAYER BUILDER TAMAMLANDI")
    print("="*80)
    print("SDK                 : READY")
    print("Module Generator    : READY")
    print("Üretilen modül      :", len(results))
    print("Errors              :", len(errors))
    print("Run All             :", run_all_path)
    print("")
    print("Şimdi çalıştır:")
    print(r'python ".py\208_Run_All.py"')

if __name__ == "__main__":
    main()
